const body = $input.first().json.body || $input.first().json;
const remoteJid = body.data?.key?.remoteJid || body.from || '';
const TARGET_GROUP = '120363409520000410@g.us';
if (remoteJid !== TARGET_GROUP) return [];

const message =
  body.message?.conversation ||
  body.message?.extendedTextMessage?.text ||
  body.text?.message ||
  body.body ||
  body.message ||
  body.data?.message?.conversation ||
  body.data?.message?.extendedTextMessage?.text ||
  '';
const textRaw = String(message).trim();

const msgObj = body.data?.message || body.message || {};
const isMedia = msgObj.audioMessage || msgObj.imageMessage || msgObj.videoMessage ||
  msgObj.stickerMessage || msgObj.documentMessage || msgObj.reactionMessage ||
  msgObj.locationMessage || msgObj.contactMessage;
if (isMedia) return [];
if (!textRaw) return [];

const sender = body.data?.key?.participant || body.sender || body.from || 'desconhecido';
const senderName = body.data?.pushName || body.senderName || body.name || sender;

// === DETECÇÃO DE COMANDO ===
// Padrões aceitos:
//   corrigir/ajustar/editar [último/ultimo] <ação>
//   deletar/apagar [último/ultimo]
const cmdMatch = textRaw.match(/^(corrigir|ajustar|editar)\s+(?:último\s+|ultimo\s+)?(.+)$/i);
const delMatch = textRaw.match(/^(deletar|apagar)\s+(?:último|ultimo)?$/i);

if (delMatch) {
  return [{ json: { isCommand: true, commandType: 'delete', sender, senderName, original: textRaw } }];
}
if (cmdMatch) {
  return [{ json: { isCommand: true, commandType: 'correct', payload: cmdMatch[2].trim(), sender, senderName, original: textRaw } }];
}

// === FILTROS PARA LANÇAMENTO NORMAL ===
if (textRaw.replace(/\s/g, '').length < 3) return [];
if (!/\d/.test(textRaw)) return [];
if (/^[/!#@]/.test(textRaw)) return [];

return [{ json: { isCommand: false, message: textRaw, sender, senderName } }];

const msg = $('🔍 Extrair Texto da Mensagem').first().json;
const aiResponse = $input.first().json.message?.content ||
  $input.first().json.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  parsed = JSON.parse(aiResponse);
} catch(e) {
  const match = aiResponse.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
}

// ====== TABELA DE CARTÕES ======
// Wesley e Sabrina compartilham config XP (mesmo fechamento/vencimento), mas tracking separado.
// Itaú só Wesley.
const CARTOES = {
  'xp wesley':  { fechamento: 6,  vencimento: 15, banco: 'XP Wesley',  aliases: ['xp w', 'xpw'] },
  'xp sabrina': { fechamento: 6,  vencimento: 15, banco: 'XP Sabrina', aliases: ['xp s', 'xps'] },
  'itau':       { fechamento: 30, vencimento: 8,  banco: 'Itaú Wesley', aliases: ['itaú', 'itau wesley', 'itaú wesley'] },
};
const CARTAO_FALLBACK = { fechamento: 1, vencimento: 10, banco: 'Crédito' };

function getCartao(nome, pessoa) {
  if (!nome) return null;
  const key = String(nome).toLowerCase().trim();
  // Match exato
  if (CARTOES[key]) return { ...CARTOES[key], chave: key };
  // Match alias
  for (const [k, c] of Object.entries(CARTOES)) {
    if (c.aliases && c.aliases.some(a => a.toLowerCase() === key)) return { ...c, chave: k };
  }
  // Desambiguação: "xp" sozinho → resolve pela pessoa que lançou
  if (key === 'xp') {
    if (pessoa === 'Sabrina') return { ...CARTOES['xp sabrina'], chave: 'xp sabrina' };
    return { ...CARTOES['xp wesley'], chave: 'xp wesley' };
  }
  return null;
}

const pad = n => String(n).padStart(2, '0');
const fmtData = d => `${pad(d.getDate())}/${pad(d.getMonth()+1)}/${d.getFullYear()}`;
const fmtComp = d => `${pad(d.getMonth()+1)}/${d.getFullYear()}`;
const fmtBR = v => Number(v).toFixed(2).replace('.', ',');

const now = new Date();
const dataLancamento = fmtData(now);

// ====== FORMA DE PAGAMENTO ======
let formaPgto = parsed.forma_pgto || 'Débito';
const cartaoNome = parsed.cartao || null;
const parcelas = Math.max(1, parseInt(parsed.parcelas) || 1);
const formaPgtoMap = {
  'debito': 'Débito', 'débito': 'Débito',
  'pix': 'PIX',
  'dinheiro': 'Dinheiro', 'especie': 'Dinheiro', 'espécie': 'Dinheiro',
  'credito': 'Crédito', 'crédito': 'Crédito',
};
formaPgto = formaPgtoMap[String(formaPgto).toLowerCase()] || formaPgto;
if (cartaoNome) formaPgto = 'Crédito';

// Default forma_pgto pra RECEITA quando IA não retornou (ou veio Débito por engano)
const tipoNorm = String(parsed.tipo || 'Despesa');
if (tipoNorm === 'Receita' && (!parsed.forma_pgto || parsed.forma_pgto === 'Débito')) {
  formaPgto = 'Crédito em conta';
}

// ====== COMPETÊNCIA BASE ======
let compBase = new Date(now.getFullYear(), now.getMonth(), 1);
if (parsed.competencia_custom) {
  const m = String(parsed.competencia_custom).match(/(\d{1,2})(?:\/(\d{4}))?/);
  if (m) {
    const month = parseInt(m[1]) - 1;
    const year = m[2] ? parseInt(m[2]) : now.getFullYear();
    compBase = new Date(year, month, 1);
  }
}

// ====== IDENTIFICAÇÃO DA PESSOA ======
const PEOPLE_LID = {
  '100515321004134@lid': 'Wesley',
  '244624274759793@lid': 'Sabrina',
  '166069373243568@lid': 'Sabrina'
};
const PEOPLE_PHONE = {
  '553191186361': 'Wesley',
  '553194349000': 'Sabrina',
  '553184822101': 'Sabrina'
};
let pessoa = 'Casal';
const senderRaw = msg.sender || '';
if (PEOPLE_LID[senderRaw]) {
  pessoa = PEOPLE_LID[senderRaw];
} else {
  const digits = senderRaw.replace(/[^0-9]/g, '');
  for (const [phone, name] of Object.entries(PEOPLE_PHONE)) {
    if (digits.includes(phone)) { pessoa = name; break; }
  }
}

const cartaoObj = getCartao(cartaoNome, pessoa);
const cartaoExibicao = cartaoObj ? cartaoObj.banco : (cartaoNome ? String(cartaoNome) : (formaPgto === 'Crédito' ? 'Crédito' : ''));

// ====== DATA CAIXA ======
function calcularDataCaixa(dataCompra, formaPgto, cartao) {
  if (formaPgto !== 'Crédito') return new Date(dataCompra);
  const c = cartao || CARTAO_FALLBACK;
  const ano = dataCompra.getFullYear();
  const mes = dataCompra.getMonth();
  const dia = dataCompra.getDate();
  // Se vencimento > fechamento, fatura vence no mesmo mês do fechamento. Senão, vence no mês seguinte.
  const sameMonth = c.vencimento > c.fechamento;
  let mesV, anoV;
  if (dia <= c.fechamento) {
    // entra na fatura desse fechamento
    mesV = sameMonth ? mes : mes + 1;
  } else {
    // entra na próxima fatura
    mesV = sameMonth ? mes + 1 : mes + 2;
  }
  anoV = ano;
  while (mesV > 11) { anoV += 1; mesV -= 12; }
  // Ajusta dia ao último do mês se vencimento não existir (ex: dia 31 em Fev)
  const ultimoDiaMes = new Date(anoV, mesV + 1, 0).getDate();
  const diaEfetivo = Math.min(c.vencimento, ultimoDiaMes);
  return new Date(anoV, mesV, diaEfetivo);
}

