const valorTotal = parsed.valor || 0;
const valorParcela = parcelas > 1 ? Math.round((valorTotal / parcelas) * 100) / 100 : valorTotal;

const items = [];
for (let i = 0; i < parcelas; i++) {
  const dcBase = calcularDataCaixa(now, formaPgto, cartaoObj);
  const dataCaixa = new Date(dcBase.getFullYear(), dcBase.getMonth() + i, dcBase.getDate());
  const compParcela = parcelas > 1 ?
    new Date(compBase.getFullYear(), compBase.getMonth() + i, 1) :
    compBase;
  const descBase = parsed.descricao || msg.message;
  const descParcela = parcelas > 1 ? `${descBase} (${i+1}/${parcelas})` : descBase;
  items.push({
    data: dataLancamento,
    data_caixa: fmtData(dataCaixa),
    competencia: fmtComp(compParcela),
    tipo: parsed.tipo || 'Despesa',
    categoria: parsed.categoria || 'Outros',
    descricao: descParcela,
    pessoa: pessoa,
    forma_pgto: formaPgto,
    cartao: cartaoExibicao,
    parcelas: parcelas,
    parcela_atual: i + 1,
    parcela_label: parcelas > 1 ? `${i+1}/${parcelas}` : '',
    valor: valorParcela,
    emoji: parsed.emoji || '💸',
    confianca: parsed.confianca || 'baixa',
    mensagem_original: msg.message,
    sender: msg.sender,
    confirmacao: '',
  });
