    `📂 ${items[0].categoria} | ${items[0].tipo}\n` +
    `👤 ${pessoa}\n` +
    `💳 ${cartaoExibicao}\n` +
    `📅 1ª caixa: ${items[0].data_caixa} (comp ${items[0].competencia})\n` +
    `🔚 última comp: ${items[parcelas-1].competencia}` +
    (items[0].confianca === 'baixa' ? '\n\n⚠️ _Baixa confiança — verifique_' : '');
} else {
  const it = items[0];
  const linhaCaixa = it.forma_pgto === 'Crédito' ? `\n💳 Caixa: ${it.data_caixa} (${cartaoExibicao})` : '';
  confirmacao = `${sinal} *Lançado com sucesso!*\n\n` +
    `${it.emoji} *${it.descricao}*\n` +
    `💰 R$ ${fmtBR(it.valor)}\n` +
    `📂 ${it.categoria} | ${it.tipo}\n` +
    `👤 ${pessoa}\n` +
    `💸 ${it.forma_pgto}` + linhaCaixa + `\n` +
    `📅 ${it.data} (comp: ${it.competencia})` +
    (it.confianca === 'baixa' ? '\n\n⚠️ _Baixa confiança — verifique_' : '');
}
items[0].confirmacao = confirmacao;

return items.map(it => ({ json: it }));

