// Detectar token Nx (parcelas) — pra corrigir parcelado é complexo; ignoro nesta versão e marco TODO
const parcelaMatch = payload.match(/(\d+)\s*x/i);

for (const t of tokens) {
  // forma pgto / cartão
  if (t === 'pix') { novoFormaPgto = 'PIX'; novoCartao = ''; acoes.push('PIX'); }
  else if (t === 'débito' || t === 'debito') { novoFormaPgto = 'Débito'; novoCartao = ''; acoes.push('Débito'); }
  else if (t === 'dinheiro') { novoFormaPgto = 'Dinheiro'; novoCartao = ''; acoes.push('Dinheiro'); }
  else if (t === 'crédito' || t === 'credito') { novoFormaPgto = 'Crédito'; acoes.push('Crédito'); }
